  legalForm:             LegalForm;
  role:                  CpRole[];
  name:                  string;
  shortName:             string;
  inn:                   string;
  kpp?:                  string;
  ogrn?:                 string;
  legalAddress?:         string;
  actualAddress?:        string;
  sameAddress:           boolean;
  phone?:                string;
  email?:                string;
  website?:              string;
  contacts:              CpContact[];
  bankName?:             string;
  bik?:                  string;
  checkingAccount?:      string;
  correspondentAccount?: string;
  founderName?:          string;
  founderNameShort?:     string;
  status:                'active' | 'inactive';
  notes?:                string;
  tags:                  string[];
  // Company profile (isOurCompany=true)
  isOurCompany?:         boolean;
  isDefaultInitiator?:   boolean;
  images?:               ProductImage[];
  footerText?:           string;
  defaultMarkupPercent?: number;
  defaultDiscountPercent?: number;
  brandingTemplates?:    BrandingTemplate[];
  createdAt:             string;
  updatedAt:             string;
