import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, shareReplay, tap } from 'rxjs';
import { environment } from '../../../environments/environment';

const BASE = environment.apiUrl;

export type ProductKind   = 'ITEM' | 'SERVICE' | 'WORK';
export type ImageContext  = 'product' | 'kp-page1' | 'kp-page2' | 'passport';
export type KpType = 'standard' | 'response' | 'special' | 'tender' | 'service';

export const KP_TYPE_LABELS: Record<KpType, string> = {
  standard: 'КП',
  response: 'Ответ на письмо',
  special: 'Спецпредложение',
  tender: 'Для тендера',
  service: 'На услуги',
};

export interface ProductImage {
  url:       string;
  isMain:    boolean;
  sortOrder: number;
  context?:  ImageContext;  // optional — backward compatible, defaults to 'product'
}

/** Factory — единственный правильный способ создавать ProductImage */
export function createImage(
  url: string,
  options: { isMain?: boolean; sortOrder?: number; context?: ImageContext } = {}
): ProductImage {
  return {
    url,
    isMain:    options.isMain    ?? false,
    sortOrder: options.sortOrder ?? 0,
    context:   options.context   ?? 'product',
  };
}

export interface Product {
  _id:          string;
  code:         string;
  name:         string;
  description:  string;
  category:     string;
  subcategory?: string;
  unit:         string;
  price:        number;
  costRub?:     number;
  images:       ProductImage[];
  isActive:     boolean;
  kind:         ProductKind;
  notes?:       string;
}

export interface Setting {
  _id:   string;
  key:   string;
  value: unknown;
  label: string;
}

export interface SettingsMap {
  kp_validity_days?:      number;
  kp_prepayment_percent?: number;
  kp_production_days?:    number;
  kp_vat_percent?:        number;
  [key: string]:          unknown;
}

export interface BackupItem {
  filename: string;
  type: 'mongo' | 'media';
  sizeBytes: number;
  createdAt: string;
}

export interface AppUser {
  _id: string;
  username: string;
  name: string;
  roleId: string | null;
  roleKey: string;
  roleName: string;
  permissions?: string[];
  isSystemRole?: boolean;
  isActive: boolean;
  mustChangePassword: boolean;
  createdAt?: string;
}

export interface Role {
  _id: string;
  name: string;
  key: string;
  isSystem: boolean;
  permissions: string[];
  createdAt?: string;
  updatedAt?: string;
}

export type PermissionModule = 'kp' | 'products' | 'counterparties' | 'users' | 'settings' | 'backups';

export interface PermissionDefinition {
  key: string;
  label: string;
  module: PermissionModule;
  description: string;
}

export type DictionaryType = 'category' | 'subcategory' | 'unit' | 'kind';

export interface Dictionary {
  _id:       string;
  type:      DictionaryType;
  value:     string;
  sortOrder: number;
  isActive:  boolean;
}

export type LegalForm = 'ООО' | 'ИП' | 'АО' | 'ПАО' | 'МКУ' | 'Физлицо' | 'Другое';
export type CpRole    = 'client' | 'supplier' | 'company';

export interface CpContact {
  name:      string;
  position?: string;
  phone?:    string;
  email?:    string;
}

export interface Counterparty {
  _id:                   string;
  legalForm:             LegalForm;
  role:                  CpRole[];
  name:                  string;
  shortName:             string;
  inn:                   string;
  kpp?:                  string;
  ogrn?:                 string;
  legalAddress?:         string;
  actualAddress?:        string;
  sameAddress:           boolean;
  phone?:                string;
  email?:                string;
  website?:              string;
  contacts:              CpContact[];
  bankName?:             string;
  bik?:                  string;
  checkingAccount?:      string;
  correspondentAccount?: string;
  founderName?:          string;
  founderNameShort?:     string;
  status:                'active' | 'inactive';
  notes?:                string;
  tags:                  string[];
  // Company profile (isOurCompany=true)
  isOurCompany?:         boolean;
  isDefaultInitiator?:   boolean;
  images?:               ProductImage[];
  footerText?:           string;
  defaultMarkupPercent?: number;
  defaultDiscountPercent?: number;
  brandingTemplates?:    BrandingTemplate[];
  createdAt:             string;
  updatedAt:             string;
}

export interface BrandingTemplate {
  key: string;
  name: string;
  kpType: KpType;
  isDefault: boolean;
  assets: {
    kpPage1: string;
    kpPage2?: string;
    passport?: string;
    appendix?: string;
  };
  conditions?: string[];
}

export interface BrandingTemplatesDto {
  kpTypes: Array<{ value: KpType; label: string }>;
  templatesByType: Partial<Record<KpType, Array<{ key: string; name: string; isDefault: boolean }>>>;
  defaultByType: Partial<Record<KpType, string>>;
}

export interface UpdateBrandingTemplatesResponse {
  message: string;
  brandingTemplates: BrandingTemplate[];
}

export interface SwitchKpTypeResponse {
  kp: Kp;
  meta: {
    conditionsReplaced: boolean;
    previousKpType: KpType;
    nextKpType: KpType;
  };
}

export interface GuestPreviewIssueResponse {
  previewUrl: string;
  expiresInSeconds: number;
}

export interface KpItem {
  productId:   string;
  code?:       string;
  name:        string;
  description: string;
  unit:        string;
  price:       number;
  qty:         number;
  imageUrl?:   string;
  markupEnabled?: boolean;
  markupPercent?: number;
  discountEnabled?: boolean;
  discountPercent?: number;
}

export interface Kp {
  _id: string;
  title: string;
  status: 'draft' | 'sent' | 'accepted' | 'rejected';
  kpType: KpType;
  counterpartyId?: string;
  companyId?:      string;
  recipient: {
    name:                  string;
    shortName?:            string;
    legalForm?:            string;
    inn?:                  string;
    kpp?:                  string;
    ogrn?:                 string;
    legalAddress?:         string;
    phone?:                string;
    email?:                string;
    bankName?:             string;
    bik?:                  string;
    checkingAccount?:      string;
    correspondentAccount?: string;
    founderName?:          string;
    founderNameShort?:     string;
  };
  metadata: {
    number: string;
    createdAt?: Date;
    validityDays: number;
    prepaymentPercent: number;
    productionDays: number;
    tablePageBreakAfter: number;
    photoScalePercent?: number;
    defaultMarkupPercent?: number;
    defaultDiscountPercent?: number;
  };
  items: KpItem[];
  conditions: string[];
  vatPercent: number;
  companySnapshot: {
    companyId: string;
    companyName: string;
    templateKey: string;
    templateName: string;
    kpType: KpType;
    assets: {
      kpPage1: string;
      kpPage2?: string;
      passport?: string;
      appendix?: string;
    };
    texts: {
      headerNote?: string;
      introText?: string;
      footerText?: string;
      closingText?: string;
    };
    requisitesSnapshot?: {
      inn?: string;
      kpp?: string;
      ogrn?: string;
      phone?: string;
      email?: string;
    };
  };
  createdAt: string;
  updatedAt: string;
}

export interface CreateKpPayload {
  title: string;
  status: 'draft' | 'sent' | 'accepted' | 'rejected';
  companyId?: string;
  kpType?: KpType;
  templateKey?: string;
  recipient: { name: string };
  items: KpItem[];
  conditions: string[];
}

@Injectable({ providedIn: 'root' })
export class ApiService {
  // shareReplay(1) — кэшируем список, не дёргаем сервер повторно
  private products$!: Observable<Product[]>;

  constructor(private http: HttpClient) {
    this.products$ = this.http.get<Product[]>(`${BASE}/products`).pipe(shareReplay(1));
  }

  getProducts(params?: { category?: string; kind?: string; isActive?: boolean; q?: string }): Observable<Product[]> {
    return this.products$;
  }

  getProductCategories(): Observable<string[]> {
    return this.http.get<string[]>(`${BASE}/products/categories`);
  }

  createProduct(data: Omit<Product, '_id'>): Observable<Product> {
    return this.http.post<Product>(`${BASE}/products`, data).pipe(
      tap(() => this.invalidateProducts())
    );
  }

  updateProduct(id: string, data: Partial<Product>): Observable<Product> {
    return this.http.put<Product>(`${BASE}/products/${id}`, data).pipe(
      tap(() => this.invalidateProducts())
    );
  }

  deleteProduct(id: string): Observable<void> {
    return this.http.delete<void>(`${BASE}/products/${id}`).pipe(
      tap(() => this.invalidateProducts())
    );
  }

  bulkImportProducts(
