import { Injectable, computed, inject } from '@angular/core';
import { toObservable } from '@angular/core/rxjs-interop';
import { AuthService } from './auth.service';
import type { AuthUser, Permission } from '../../../../../shared/types/User';

@Injectable({ providedIn: 'root' })
export class PermissionsService {
  private readonly auth = inject(AuthService);
  readonly currentUser = this.auth.currentUser;
  readonly currentUser$ = toObservable(this.currentUser);
  readonly permissions = computed(() => {
    const user = this.currentUser();
    if (!user || !user.isActive) return [] as Permission[];
    return user.permissions ?? [];
  });

  can(permission: Permission): boolean {
    return this.permissions().includes(permission);
  }
}

import { Injectable, signal } from '@angular/core';

export type ThemeMode = 'light' | 'dark';

@Injectable({ providedIn: 'root' })
export class ThemeService {
  readonly mode = signal<ThemeMode>('light');

  constructor() {
    const saved = localStorage.getItem('kppdf-theme');
    const initial: ThemeMode = saved === 'dark' ? 'dark' : 'light';
    this.apply(initial);
  }

  toggle() {
    this.apply(this.mode() === 'dark' ? 'light' : 'dark');
  }

  private apply(mode: ThemeMode) {
    this.mode.set(mode);
    document.documentElement.setAttribute('data-theme', mode);
    localStorage.setItem('kppdf-theme', mode);
  }
}

