  readonly loading = signal(true);
  readonly error = signal<string | null>(null);

  constructor() {
    const token = this.route.snapshot.paramMap.get('token');
    if (!token) {
      this.loading.set(false);
      this.error.set('Ссылка гостевого просмотра некорректна.');
