        error: (err) => {
          this.loading.set(false);
          this.error.set(err?.error?.message ?? 'Не удалось открыть гостевой просмотр.');
        }
      });
  }

  goToLogin(): void {
    this.router.navigateByUrl('/login');
  }
}

