    background: color-mix(in srgb, var(--section-accent) 10%, var(--ui-bg));
    color: var(--section-accent);
    cursor: pointer;
  }

  &--recipient {
    --section-bg: color-mix(in srgb, var(--ui-primary) 10%, var(--ui-bg));
    --section-border: color-mix(in srgb, var(--ui-primary) 26%, var(--ui-border));
