  }

  span {
    font-size: $font-xs;
    color: var(--ui-text-muted);
  }
}

.recipient-readonly-hint {
  margin: $space-2 0 0;
  font-size: $font-xs;
  color: var(--ui-text-muted);
}

.inn-lookup {
  display: flex;
  gap: $space-2;
  margin-bottom: $space-2;

  &__input {
    flex: 1;
    border: 1px solid var(--ui-border);
    border-radius: $radius-md;
    padding: 0.4rem $space-3;
    font-size: $font-sm;
    font-family: inherit;
    box-sizing: border-box;
    background: var(--ui-bg);
    color: var(--ui-text);
    &:focus-visible { outline: none; border-color: var(--ui-primary); }
