  font-size: $font-sm;

  strong { color: color-mix(in srgb, var(--ui-primary) 78%, var(--ui-text)); font-size: $font-md; }
}

@use '../../../../styles/tokens' as *;

.product-row {
  display: flex;
  align-items: center;
  gap: $space-2;
  padding: $space-3;
  border: 0.5px solid var(--ui-border-light);
  border-radius: var(--radius-lg);
  background: var(--ui-bg-card, var(--ui-bg));
  box-shadow: var(--shadow-sm);
  transition: transform 0.2s ease, box-shadow 0.2s ease;

