  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: $space-3;
}

.catalog-tools {
  display: grid;
  grid-template-columns: 1fr 11.25rem;
  gap: $space-2;
  margin-bottom: $space-3;

  &__search,
  &__select {
    width: 100%;
    border: 1px solid color-mix(in srgb, var(--ui-text-main) 6%, transparent);
    border-radius: $radius-md;
    padding: 0.45rem $space-2;
    font-size: $font-sm;
    font-family: inherit;
    box-sizing: border-box;
  }
}

@media (max-width: 1220px) {
  .product-grid {
    grid-template-columns: 1fr;
  }
}

.item-row {
  display: grid;
  grid-template-columns: 2.75rem minmax(0, 1fr) auto;
  gap: $space-1;
  padding: $space-1 0;
  border-bottom: 1px solid color-mix(in srgb, var(--ui-text-main) 5%, transparent);
  font-size: $font-sm;

  &__thumb {
    width: 2.75rem;
    height: 2.75rem;
    border-radius: $radius-sm;
    border: 1px solid var(--ui-border-light);
    background: var(--ui-bg-soft);
    overflow: hidden;
    display: flex;
    align-items: center;
    justify-content: center;
    align-self: start;

    img {
      width: 100%;
      height: 100%;
      object-fit: cover;
      display: block;
    }

    span {
      font-size: 0.75rem;
      color: var(--ui-text-muted);
      text-align: center;
      line-height: 1.1;
      padding: 0 $space-1;
    }
  }

  &__meta {
    min-width: 0;
  }

  &__select {
    display: inline-flex;
    align-items: center;
    gap: $space-2;
    margin-bottom: $space-1;
    font-size: 0.75rem;
    color: var(--ui-text-muted);
  }

  &__name {
    display: block;
    font-weight: 600;
    font-size: 0.9rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  &__code {
    display: block;
    margin-top: $space-1;
    color: var(--ui-text-muted);
    font-size: 0.82rem;
  }

  &__price {
    display: block;
    margin-top: $space-1;
    font-size: 0.75rem;
    color: var(--ui-text-muted);
  }

  &__applied {
    display: inline-block;
    margin-top: $space-1;
    font-size: 0.75rem;
    font-weight: 600;
    color: var(--ui-success);
  }

  &__formula {
    display: block;
    margin-top: $space-1;
    font-size: 0.75rem;
    color: var(--ui-text-muted);
    line-height: 1.25;
  }

  &__controls {
    grid-column: 3 / 4;
    display: flex;
    flex-direction: column;
    align-items: flex-end;
    gap: $space-1;
    justify-content: flex-start;
  }

  &__stepper {
    display: inline-flex;
    align-items: center;
    gap: 2px;
    padding: 2px;
    border-radius: 8px;
    background: color-mix(in srgb, var(--ui-bg-soft) 88%, var(--ui-bg));
  }

  &__stepper [ui-btn].btn--icon {
    min-width: 1.5rem;
    min-height: 1.5rem;
    width: 1.5rem;
    height: 1.5rem;
    border-radius: 6px;
    border: 1px solid color-mix(in srgb, var(--ui-text-main) 7%, transparent);
    background: color-mix(in srgb, var(--ui-bg) 92%, var(--ui-bg-soft));
    font-size: 0.8125rem;
  }

  &__qty {
    width: 2.25rem;
    height: 1.5rem;
    border: none;
    border-radius: 6px;
    padding: 0.0625rem 0.25rem;
    text-align: center;
    font-size: 0.75rem;
    font-weight: 600;
    font-family: inherit;
    background: transparent;
  }

  &__total {
    font-size: 0.8125rem;
    font-weight: 700;
    color: var(--ui-text-main);
    line-height: 1.1;
  }

  &__remove {
    align-self: start;
    margin-left: $space-1;
    width: 1.125rem;
    height: 1.125rem;
    border: none;
    border-radius: 999px;
    background: color-mix(in srgb, var(--ui-danger) 78%, transparent);
    color: var(--ui-text-on-primary);
    font-size: 0.75rem;
    line-height: 1;
    cursor: pointer;
    opacity: 0;
    transition: opacity 0.15s ease, transform 0.15s ease;
  }

  &:hover &__remove,
  &:focus-within &__remove {
    opacity: 1;
  }

  &__remove:active {
    transform: scale(0.95);
  }

}

.manual-item-form {
  display: flex;
  justify-content: flex-start;
  margin: $space-2 0 $space-3;
}

.bulk-adjustments {
  display: grid;
  gap: $space-2;
  margin-bottom: $space-3;
  padding: $space-2;
  border: none;
  border-radius: $radius-md;
  background: color-mix(in srgb, var(--ui-primary) 4%, var(--ui-bg));

  &__row {
    display: grid;
    grid-template-columns: minmax(0, 1fr);
    gap: $space-2;
    align-items: end;
  }

  label {
    display: grid;
    gap: $space-1;
    font-size: 0.75rem;
    color: var(--ui-text-muted);
  }

  input {
    width: 100%;
    max-width: 6.5rem;
    height: 1.875rem;
    border: 1px solid var(--ui-border);
    border-radius: $radius-sm;
    padding: $space-1 $space-2;
    font-size: 0.86rem;
    font-family: inherit;
  }

  &__actions {
    display: flex;
    align-items: center;
    justify-content: flex-start;
    flex-wrap: wrap;
    gap: $space-2;
    font-size: 0.75rem;
    color: var(--ui-text-muted);
  }
}

.condition-row {
  display: flex;
  align-items: center;
  gap: $space-2;
  margin-bottom: $space-2;
  min-width: 0;

  input {
    margin-bottom: 0;
    flex: 1;
    min-width: 0;
  }

  button {
    flex-shrink: 0;
  }
}

.condition-templates {
  display: grid;
  gap: $space-2;
  margin-bottom: $space-2;

  button {
    width: 100%;
    justify-content: flex-start;
    text-align: left;
    white-space: normal;
    line-height: 1.35;
    border-color: transparent;
    background: transparent;
    color: var(--ui-text-muted);
  }
}

.template-variables-hint {
  margin-bottom: $space-2;
  padding: $space-2;
  border: 1px solid color-mix(in srgb, var(--ui-text-main) 8%, transparent);
  border-radius: $radius-md;
  background: color-mix(in srgb, var(--ui-primary) 3%, var(--ui-bg));

  &__title {
    margin: 0 0 $space-1;
    font-size: 0.75rem;
    font-weight: 600;
    color: var(--ui-text-main);
  }

  &__list {
    margin: 0;
    padding-left: 1rem;
    display: grid;
    gap: 0.25rem;
    font-size: 0.75rem;
    color: var(--ui-text-muted);
  }

  code {
    font-size: 0.75rem;
    font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;
    color: var(--ui-text-main);
    background: color-mix(in srgb, var(--ui-bg-soft) 90%, var(--ui-bg));
    border: 1px solid color-mix(in srgb, var(--ui-text-main) 10%, transparent);
    border-radius: 6px;
    padding: 0.125rem 0.35rem;
  }
}

.kp-params-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: $space-2;

  &__field {
    display: grid;
    gap: $space-1;

    span {
      font-size: $font-xs;
      color: var(--ui-text-muted);
      text-transform: none;
      letter-spacing: 0.01em;
    }

    input {
      margin-bottom: 0;
      width: 100%;
      border: 1px solid var(--ui-border);
      border-radius: $radius-md;
      padding: 0.4rem $space-2;
      font-size: $font-sm;
      font-family: inherit;
      box-sizing: border-box;
    }
  }

  &__field--wide {
    grid-column: 1 / -1;
  }
}

.template-picker {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: $space-2;
  align-items: center;

  select,
  input {
    margin-bottom: 0;
  }

  &__open-btn {
    width: 2rem;
    min-width: 2rem !important;
    height: 2rem;
    padding: 0 !important;
    line-height: 1;
    font-size: 1rem;
    border-radius: $radius-sm;
  }
}

.photo-scale-control {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto 4.5rem;
  align-items: center;
  gap: $space-2;

  &__range {
    appearance: none;
    height: 0.375rem;
    border: none !important;
    border-radius: 999px !important;
    background: color-mix(in srgb, var(--ui-primary) 22%, var(--ui-bg-soft));
    padding: 0 !important;
    margin: 0;

    &::-webkit-slider-thumb {
      appearance: none;
      width: 1rem;
      height: 1rem;
      border-radius: 50%;
      background: var(--ui-primary);
      border: 2px solid var(--ui-bg);
      box-shadow: 0 1px 4px color-mix(in srgb, var(--ui-primary) 42%, transparent);
      cursor: pointer;
    }

    &::-moz-range-thumb {
      width: 1rem;
      height: 1rem;
      border-radius: 50%;
      background: var(--ui-primary);
      border: 2px solid var(--ui-bg);
      box-shadow: 0 1px 4px color-mix(in srgb, var(--ui-primary) 42%, transparent);
      cursor: pointer;
    }
  }

  &__value {
    font-size: $font-xs;
    color: var(--ui-text-muted);
    min-width: 40px;
    text-align: right;
    font-variant-numeric: tabular-nums;
  }

  &__number {
    margin-bottom: 0;
    text-align: center;
    font-variant-numeric: tabular-nums;
  }
}

@media (max-width: 1024px) {
  .kp-params-grid {
    grid-template-columns: 1fr;

    &__field--wide {
      grid-column: auto;
    }
  }

  .photo-scale-control {
    grid-template-columns: minmax(0, 1fr) auto;

    &__number {
      grid-column: 1 / -1;
    }
  }
}

/* Density pass for all KP side-panel actions */
.builder__sidebar [ui-btn],
.builder__right [ui-btn] {
  --ui-btn-height: 2rem;
  border-radius: $radius-sm;
}

.builder__sidebar [ui-btn].btn--sm,
.builder__right [ui-btn].btn--sm {
  --ui-btn-height: 2rem;
  padding-inline: $space-2;
  font-size: $font-xs;
}

.builder__sidebar [ui-btn].btn--icon,
.builder__right [ui-btn].btn--icon {
  min-width: 2rem;
  min-height: 2rem;
  padding: 0;
  border: 1px solid color-mix(in srgb, var(--ui-text-main) 6%, transparent);
  border-radius: 999px;
  background: color-mix(in srgb, var(--ui-bg-soft) 90%, var(--ui-bg));
  color: var(--ui-text-muted);
}

.builder__sidebar [ui-btn].btn--icon:hover,
.builder__right [ui-btn].btn--icon:hover {
  background: color-mix(in srgb, var(--ui-primary) 8%, var(--ui-bg));
  border-color: color-mix(in srgb, var(--ui-border) 70%, var(--ui-primary));
  color: var(--ui-text);
}

.builder__sidebar [ui-btn].btn--icon:focus-visible,
.builder__right [ui-btn].btn--icon:focus-visible {
  box-shadow: 0 0 0 3px var(--ui-primary-focus);
}

