import { ChangeDetectionStrategy, Component, input, computed, output } from '@angular/core';
import { CommonModule } from '@angular/common';
import { KpBackgroundComponent } from '../kp-background/kp-background.component';
import { KpHeaderComponent, type KpRecipient, type KpMetadata } from '../kp-header/kp-header.component';
import { KpCatalogComponent, type KpCatalogItem, type PriceChangedEvent } from '../kp-catalog/kp-catalog.component';
import { KpTableComponent, type KpTotals } from '../kp-table/kp-table.component';
import { KpTemplatePipe } from '../template-pipe/template.pipe';

interface KpPageChunk {
  items: KpCatalogItem[];
  displayOffset: number;
  useFirstBackground: boolean;
  showHeader: boolean;
  showTotals: boolean;
}

interface CompanySnapshot {
  companyId: string;
  companyName: string;
  templateKey: string;
  templateName: string;
  kpType: 'standard' | 'response' | 'special' | 'tender' | 'service';
  assets: {
    kpPage1: string;
    kpPage2?: string;
    passport?: string;
    appendix?: string;
  };
  texts: {
    headerNote?: string;
    introText?: string;
    footerText?: string;
    closingText?: string;
  };
}

@Component({
  selector: 'app-kp-document',
  standalone: true,
  imports: [
    CommonModule, 
    KpBackgroundComponent, 
    KpHeaderComponent, 
    KpCatalogComponent, 
    KpTableComponent,
    KpTemplatePipe
  ],
  templateUrl: './kp-document.component.html',
  styleUrl: './kp-document.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class KpDocumentComponent {
  itemsPerPage = input(10);

  recipient = input<KpRecipient>({
    name: 'ООО "Пример Компания"',
    inn: '1234567890',
    email: 'info@example.com',
    phone: '+7 (999) 123-45-67'
  });

  metadata = input<KpMetadata>({
    number: 'КП-2024-001',
    validityDays: 10,
    prepaymentPercent: 50,
    productionDays: 15,
    tablePageBreakAfter: 6,
    photoScalePercent: 150
  });

  items = input<KpCatalogItem[]>([]);
  editablePrices = input(false);
  conditions = input<string[]>([]);
  vatPercent = input<number>(20);
  companySnapshot = input.required<CompanySnapshot>();
  priceChanged = output<PriceChangedEvent>();

  protected readonly totals = computed((): KpTotals => {
    const subtotal = this.items().reduce((s, i) => s + i.price * i.qty, 0);
    const vatPercent = this.vatPercent();
    const vatAmount = Math.round(subtotal * vatPercent / (100 + vatPercent));
    return { subtotal, vatPercent, vatAmount, total: subtotal };
  });

  protected readonly hasDescriptionColumn = computed(() =>
    this.items().some(item => (item.description ?? '').trim().length > 0)
  );

  protected readonly hasPhotoColumn = computed(() =>
    this.items().some(item => (item.imageUrl ?? '').trim().length > 0)
  );

  protected readonly hasCodeColumn = computed(() =>
    this.items().some(item => (item.code ?? '').trim().length > 0)
  );

  protected readonly resolvedItemsPerPage = computed(() =>
    Math.max(1, Number(this.itemsPerPage()) || 6)
  );

  protected readonly pageChunks = computed((): KpPageChunk[] => {
    const chunks: KpPageChunk[] = [];
    const perPage = this.resolvedItemsPerPage();
    const allItems = this.items();

    if (allItems.length === 0) {
      return [{ items: [], displayOffset: 0, useFirstBackground: true, showHeader: true, showTotals: true }];
    }

    for (let i = 0; i < allItems.length; i += perPage) {
      const pageItems = allItems.slice(i, i + perPage);
      const isFirst = i === 0;
      const isLast = i + perPage >= allItems.length;
      chunks.push({ items: pageItems, displayOffset: i, useFirstBackground: isFirst, showHeader: isFirst, showTotals: isLast });
    }
    return chunks;
  });

  protected readonly totalPages = computed(() => this.pageChunks().length);

  protected backgroundForPage(pageIndex: number): string | null {
    const snapshot = this.companySnapshot();
    return pageIndex === 0
      ? (snapshot.assets.kpPage1 || null)
      : (snapshot.assets.kpPage2 || null);
  }

  protected headerNote(): string {
    return String(this.companySnapshot().texts?.headerNote ?? '').trim();
  }

  protected introText(): string {
    return String(this.companySnapshot().texts?.introText ?? '').trim();
  }

  protected closingText(): string {
    return String(this.companySnapshot().texts?.closingText ?? '').trim();
  }

  protected documentFooter(): string {
    return String(this.companySnapshot().texts?.footerText ?? '').trim();
  }
}

import { Component, input } from '@angular/core';
import { CommonModule } from '@angular/common';
import { KpType } from '../../../../core/services/api.service';

export interface KpRecipient {
  name:                  string;
  shortName?:            string;
  legalForm?:            string;
  inn?:                  string;
  kpp?:                  string;
  ogrn?:                 string;
  legalAddress?:         string;
  phone?:                string;
  email?:                string;
  bankName?:             string;
  bik?:                  string;
  checkingAccount?:      string;
  correspondentAccount?: string;
  founderName?:          string;
  founderNameShort?:     string;
}

export interface KpMetadata {
  number:            string;
  createdAt?:        Date;
  validityDays:      number;
  prepaymentPercent: number;
  productionDays:    number;
  tablePageBreakAfter: number;
  photoScalePercent?: number;
}

@Component({
  selector: 'app-kp-header',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './kp-header.component.html',
  styleUrl: './kp-header.component.scss'
})
export class KpHeaderComponent {
  recipient = input.required<KpRecipient>();
  metadata  = input.required<KpMetadata>();
  kpType = input<KpType>('standard');

  protected recipientDisplayName(): string {
    const recipient = this.recipient();
    const baseName = (recipient.shortName || recipient.name || '').trim();
    const legalForm = (recipient.legalForm || '').trim();

    if (!legalForm || legalForm === 'Физлицо') {
      return `"${baseName}"`;
    }

    if (baseName.toLowerCase().startsWith(legalForm.toLowerCase())) {
      return `"${baseName}"`;
    }

    return `${legalForm} "${baseName}"`;
  }

  protected displayDate(): Date {
    const value = this.metadata().createdAt;
    if (!value) return new Date();
    return value instanceof Date ? value : new Date(value);
  }

  protected introTitle(): string {
    const kpType = this.kpType();
    if (kpType === 'response') return 'Ответ на письмо для:';
    return 'Коммерческое предложение для:';
  }
}

import { Component, input } from '@angular/core';
import { CommonModule } from '@angular/common';
import { KpTemplatePipe } from '../template-pipe/template.pipe';

export interface KpTotals {
  subtotal: number;
  vatPercent: number;
  vatAmount: number;
  total: number;
}

@Component({
  selector: 'app-kp-table',
  standalone: true,
  imports: [CommonModule, KpTemplatePipe],
  templateUrl: './kp-table.component.html',
  styleUrl: './kp-table.component.scss'
})
export class KpTableComponent {
  totals = input.required<KpTotals>();
  conditions = input<string[]>([]);
}

import { Component, signal, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { FormFieldComponent, AlertComponent, ButtonComponent } from '../../shared/ui/index';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [CommonModule, FormsModule, FormFieldComponent, AlertComponent, ButtonComponent],
  templateUrl: './login.component.html',
  styleUrl: './login.component.scss'
})
export class LoginComponent {
  private readonly auth   = inject(AuthService);
  private readonly router = inject(Router);

  username = '';
  password = '';
  guestLink = '';
  loading  = signal(false);
  error    = signal('');

  submit() {
    if (!this.username || !this.password) {
      this.error.set('Введите логин и пароль');
      return;
    }
    this.loading.set(true);
    this.error.set('');

    this.auth.login(this.username, this.password).subscribe({
      next:  () => this.router.navigate(['/']),
      error: err => {
        this.loading.set(false);
        this.error.set(err.error?.message ?? 'Ошибка входа');
      }
    });
  }

  enterGuest(): void {
    const raw = this.guestLink.trim();
    if (!raw) {
      this.error.set('Вставьте гостевую ссылку или токен');
      return;
    }

    const token = this.extractGuestToken(raw);
    if (!token) {
      this.error.set('Не удалось распознать токен гостевого доступа');
      return;
    }

    this.error.set('');
    this.router.navigate(['/guest-preview', token]);
  }

  private extractGuestToken(input: string): string | null {
    const directMatch = input.match(/\/guest-preview\/([^/?#]+)/i);
    if (directMatch?.[1]) return directMatch[1];
    if (/^[A-Za-z0-9\-_]+\.[A-Za-z0-9\-_]+\.[A-Za-z0-9\-_]+$/.test(input)) return input;
    return null;
  }
}

